<?php
 namespace WPAICG\Core\Providers\OpenAI\Methods; use WPAICG\Core\Providers\OpenAIProviderStrategy; use WPAICG\Core\Providers\OpenAI\OpenAIUrlBuilder; use WPAICG\Core\AIPKit_Models_API; use WP_Error; if (!defined('ABSPATH')) { exit; } function get_models_logic(OpenAIProviderStrategy $strategyInstance, array $api_params): array|WP_Error { $url_builder_params = [ 'base_url' => $api_params['base_url'] ?? 'https://api.openai.com', 'api_version' => $api_params['api_version'] ?? 'v1', ]; $url = OpenAIUrlBuilder::build('models', $url_builder_params); if (is_wp_error($url)) { return $url; } $headers = $strategyInstance->get_api_headers($api_params['api_key'], 'models'); $options = $strategyInstance->get_request_options('models'); $options['method'] = 'GET'; $response = wp_remote_get($url, array_merge($options, ['headers' => $headers])); if (is_wp_error($response)) { return $response; } $status_code = wp_remote_retrieve_response_code($response); $body = wp_remote_retrieve_body($response); if ($status_code !== 200) { $error_msg = $strategyInstance->parse_error_response($body, $status_code); return new WP_Error('api_error_openai_models_logic', sprintf('OpenAI API Error (HTTP %d): %s', $status_code, esc_html($error_msg))); } $decoded = $strategyInstance->decode_json_public($body, 'OpenAI Models'); if (is_wp_error($decoded)) { return $decoded; } $raw_models = $decoded['data'] ?? []; if (!class_exists(\WPAICG\Core\AIPKit_Models_API::class)) { $models_api_path = WPAICG_PLUGIN_DIR . 'classes/core/models_api.php'; if(file_exists($models_api_path)) { require_once $models_api_path; } else { return $strategyInstance->format_model_list($raw_models); } } return $strategyInstance->format_model_list($raw_models); }